import{i as e,r as t,s as n,t as r}from"./app-B1jqjtqq.js";var i=JSON.parse(`{"path":"/linux-tutor/awesome-shell/awesome-scripts.html","title":"实用 Shell 脚本合集","lang":"zh-CN","frontmatter":{"description":"实用 Shell 脚本合集 精选日常运维中常用的 Shell 脚本，涵盖日志管理、网络监控、系统巡检、文件处理等场景。 一、日志管理 1. 定时清空文件内容 每小时执行一次，当时间为 0 点或 12 点时清空目标目录下所有文件内容，其他时间记录文件大小： 2. 监测 Nginx 502 错误并自动恢复 3. 日志自动清理（保留最近 N 天） 二、网络监...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"实用 Shell 脚本合集\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-15T12:37:10.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/linux-tutor/awesome-shell/awesome-scripts.html"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"实用 Shell 脚本合集"}],["meta",{"property":"og:description","content":"实用 Shell 脚本合集 精选日常运维中常用的 Shell 脚本，涵盖日志管理、网络监控、系统巡检、文件处理等场景。 一、日志管理 1. 定时清空文件内容 每小时执行一次，当时间为 0 点或 12 点时清空目标目录下所有文件内容，其他时间记录文件大小： 2. 监测 Nginx 502 错误并自动恢复 3. 日志自动清理（保留最近 N 天） 二、网络监..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-15T12:37:10.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-15T12:37:10.000Z"}]]},"git":{"createdTime":1784119030000,"updatedTime":1784119030000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":1,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":5.07,"words":1522},"filePathRelative":"linux-tutor/awesome-shell/awesome-scripts.md","autoDesc":true}`),a={name:`awesome-scripts.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="实用-shell-脚本合集" tabindex="-1"><a class="header-anchor" href="#实用-shell-脚本合集"><span>实用 Shell 脚本合集</span></a></h1><blockquote><p>精选日常运维中常用的 Shell 脚本，涵盖日志管理、网络监控、系统巡检、文件处理等场景。</p></blockquote><h2 id="一、日志管理" tabindex="-1"><a class="header-anchor" href="#一、日志管理"><span>一、日志管理</span></a></h2><h3 id="_1-定时清空文件内容" tabindex="-1"><a class="header-anchor" href="#_1-定时清空文件内容"><span>1. 定时清空文件内容</span></a></h3><p>每小时执行一次，当时间为 0 点或 12 点时清空目标目录下所有文件内容，其他时间记录文件大小：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 用法: 配合 crontab 每小时执行一次</span></span>
<span class="line"><span class="token assign-left variable">logfile</span><span class="token operator">=</span>/tmp/<span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> +%H-%F<span class="token variable">)</span></span>.log</span>
<span class="line"><span class="token assign-left variable">hour</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> +%H<span class="token variable">)</span></span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$hour</span>&quot;</span> <span class="token parameter variable">-eq</span> 00 <span class="token punctuation">]</span> <span class="token operator">||</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$hour</span>&quot;</span> <span class="token parameter variable">-eq</span> <span class="token number">12</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token comment"># 清空所有文件内容</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token for-or-select variable">file</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">find</span> /data/log/ <span class="token parameter variable">-type</span> f<span class="token variable">)</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">        <span class="token boolean">true</span> <span class="token operator">&gt;</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span></span>
<span class="line">    <span class="token keyword">done</span></span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line">    <span class="token comment"># 记录文件大小</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token for-or-select variable">file</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">find</span> /data/log/ <span class="token parameter variable">-type</span> f<span class="token variable">)</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">        <span class="token function">du</span> <span class="token parameter variable">-sh</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token operator">&gt;&gt;</span> <span class="token string">&quot;<span class="token variable">$logfile</span>&quot;</span></span>
<span class="line">    <span class="token keyword">done</span></span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-监测-nginx-502-错误并自动恢复" tabindex="-1"><a class="header-anchor" href="#_2-监测-nginx-502-错误并自动恢复"><span>2. 监测 Nginx 502 错误并自动恢复</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 监测 Nginx 访问日志，发现大量 502 错误时自动重启 php-fpm</span></span>
<span class="line"><span class="token assign-left variable">log</span><span class="token operator">=</span>/data/log/access.log</span>
<span class="line"><span class="token assign-left variable">threshold</span><span class="token operator">=</span><span class="token number">30</span>  <span class="token comment"># 300 条日志中 502 数量阈值</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">while</span> <span class="token builtin class-name">:</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token comment"># 查看最近 300 条日志，统计 502 数量</span></span>
<span class="line">    <span class="token assign-left variable">err_count</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">tail</span> <span class="token parameter variable">-n</span> <span class="token number">300</span> <span class="token string">&quot;<span class="token variable">$log</span>&quot;</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-c</span> <span class="token string">&#39;502&quot; &#39;</span><span class="token variable">)</span></span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$err_count</span>&quot;</span> <span class="token parameter variable">-ge</span> <span class="token string">&quot;<span class="token variable">$threshold</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        /etc/init.d/php-fpm restart <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null</span>
<span class="line">        <span class="token function">sleep</span> <span class="token number">60</span>  <span class="token comment"># 防止频繁重启</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line">    <span class="token function">sleep</span> <span class="token number">10</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre></div><h3 id="_3-日志自动清理-保留最近-n-天" tabindex="-1"><a class="header-anchor" href="#_3-日志自动清理-保留最近-n-天"><span>3. 日志自动清理（保留最近 N 天）</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 清理指定目录下 N 天前的日志文件</span></span>
<span class="line"><span class="token assign-left variable">log_dir</span><span class="token operator">=</span><span class="token string">&quot;/var/log/nginx&quot;</span></span>
<span class="line"><span class="token assign-left variable">retention_days</span><span class="token operator">=</span><span class="token number">30</span></span>
<span class="line"></span>
<span class="line"><span class="token function">find</span> <span class="token string">&quot;<span class="token variable">$log_dir</span>&quot;</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.log&quot;</span> <span class="token parameter variable">-type</span> f <span class="token parameter variable">-mtime</span> +<span class="token variable">$retention_days</span> <span class="token parameter variable">-exec</span> <span class="token function">rm</span> <span class="token parameter variable">-f</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;[<span class="token variable"><span class="token variable">$(</span><span class="token function">date</span><span class="token variable">)</span></span>] 清理完成，已删除 <span class="token variable">$retention_days</span> 天前的日志&quot;</span> <span class="token operator">&gt;&gt;</span> /var/log/cleanup.log</span>
<span class="line"></span></code></pre></div><h2 id="二、网络监控" tabindex="-1"><a class="header-anchor" href="#二、网络监控"><span>二、网络监控</span></a></h2><h3 id="_4-检测网卡流量并记录" tabindex="-1"><a class="header-anchor" href="#_4-检测网卡流量并记录"><span>4. 检测网卡流量并记录</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 每分钟检测网卡流量并记录到日志</span></span>
<span class="line"><span class="token assign-left variable">interface</span><span class="token operator">=</span><span class="token string">&quot;eth0&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">while</span> <span class="token builtin class-name">:</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token assign-left variable"><span class="token environment constant">LANG</span></span><span class="token operator">=</span>en</span>
<span class="line">    <span class="token assign-left variable">logfile</span><span class="token operator">=</span><span class="token string">&quot;/tmp/<span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> +%d<span class="token variable">)</span></span>.log&quot;</span></span>
<span class="line">    <span class="token builtin class-name">exec</span> <span class="token operator">&gt;&gt;</span> <span class="token string">&quot;<span class="token variable">$logfile</span>&quot;</span></span>
<span class="line">    <span class="token function">date</span> +<span class="token string">&quot;%F %H:%M&quot;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment"># sar 统计流量，单位 kb/s，转换为 bps</span></span>
<span class="line">    sar <span class="token parameter variable">-n</span> DEV <span class="token number">1</span> <span class="token number">59</span> <span class="token operator">|</span> <span class="token function">grep</span> Average <span class="token operator">|</span> <span class="token function">grep</span> <span class="token string">&quot;<span class="token variable">$interface</span>&quot;</span> <span class="token operator">|</span> <span class="token punctuation">\\</span></span>
<span class="line">        <span class="token function">awk</span> <span class="token string">&#39;{print $2,&quot;\\tinput:\\t&quot;,$5*1000*8,&quot;bps&quot;,&quot;\\n&quot;,$2,&quot;\\toutput:\\t&quot;,$6*1000*8,&quot;bps&quot;}&#39;</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;####################&quot;</span></span>
<span class="line">    <span class="token comment"># sar 执行需要 59 秒，因此无需 sleep</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-批量测试服务器连通性" tabindex="-1"><a class="header-anchor" href="#_5-批量测试服务器连通性"><span>5. 批量测试服务器连通性</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 测试多个服务器是否在线</span></span>
<span class="line"><span class="token assign-left variable">servers</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token string">&quot;192.168.1.1&quot;</span> <span class="token string">&quot;192.168.1.2&quot;</span> <span class="token string">&quot;192.168.1.3&quot;</span> <span class="token string">&quot;8.8.8.8&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">server</span> <span class="token keyword">in</span> <span class="token string">&quot;<span class="token variable">\${servers<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>&quot;</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token function">ping</span> <span class="token parameter variable">-c</span> <span class="token number">2</span> <span class="token parameter variable">-W</span> <span class="token number">3</span> <span class="token string">&quot;<span class="token variable">$server</span>&quot;</span> <span class="token operator">&amp;&gt;</span>/dev/null<span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;✅ <span class="token variable">$server</span> 可达&quot;</span></span>
<span class="line">    <span class="token keyword">else</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;❌ <span class="token variable">$server</span> 不可达&quot;</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre></div><h3 id="_6-检测端口是否开放" tabindex="-1"><a class="header-anchor" href="#_6-检测端口是否开放"><span>6. 检测端口是否开放</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 检查远程主机端口是否开放</span></span>
<span class="line"><span class="token assign-left variable">host</span><span class="token operator">=</span><span class="token string">&quot;192.168.1.100&quot;</span></span>
<span class="line"><span class="token assign-left variable">ports</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token number">22</span> <span class="token number">80</span> <span class="token number">443</span> <span class="token number">3306</span> <span class="token number">6379</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">port</span> <span class="token keyword">in</span> <span class="token string">&quot;<span class="token variable">\${ports<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>&quot;</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token function">timeout</span> <span class="token number">3</span> <span class="token function">bash</span> <span class="token parameter variable">-c</span> <span class="token string">&quot;echo &gt;/dev/tcp/<span class="token variable">$host</span>/<span class="token variable">$port</span>&quot;</span> <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null <span class="token operator">&amp;&amp;</span> <span class="token punctuation">\\</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;✅ <span class="token variable">$host</span>:<span class="token variable">$port</span> 开放&quot;</span> <span class="token operator">||</span> <span class="token punctuation">\\</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;❌ <span class="token variable">$host</span>:<span class="token variable">$port</span> 关闭&quot;</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre></div><h2 id="三、系统巡检" tabindex="-1"><a class="header-anchor" href="#三、系统巡检"><span>三、系统巡检</span></a></h2><h3 id="_7-服务器系统信息收集" tabindex="-1"><a class="header-anchor" href="#_7-服务器系统信息收集"><span>7. 服务器系统信息收集</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 收集服务器基本信息</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;========== 系统信息 ==========&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;主机名: <span class="token variable"><span class="token variable">$(</span><span class="token function">hostname</span><span class="token variable">)</span></span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;系统: <span class="token variable"><span class="token variable">$(</span><span class="token function">uname</span> <span class="token parameter variable">-a</span><span class="token variable">)</span></span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;CPU: <span class="token variable"><span class="token variable">$(</span>nproc<span class="token variable">)</span></span> 核&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;内存: <span class="token variable"><span class="token variable">$(</span><span class="token function">free</span> <span class="token parameter variable">-h</span> <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;/Mem:/ {print $3 &quot;/&quot; $2}&#39;</span><span class="token variable">)</span></span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;磁盘: $(df -h / | awk &#39;NR==2 {print <span class="token variable">$3</span> &quot;/&quot; <span class="token variable">$2</span> &quot; (&quot; <span class="token variable">$5</span> &quot;)&quot;</span><span class="token punctuation">}</span><span class="token string">&#39;)&quot;</span>
<span class="line">echo &quot;运行时间: $(uptime | awk &#39;</span><span class="token punctuation">{</span>print <span class="token variable">$3</span>,<span class="token variable">$4</span><span class="token punctuation">}</span><span class="token string">&#39; | tr -d &#39;</span>,<span class="token string">&#39;)&quot;</span>
<span class="line">echo &quot;负载: $(uptime | awk -F&#39;</span>load average:<span class="token string">&#39; &#39;</span><span class="token punctuation">{</span>print <span class="token variable">$2</span><span class="token punctuation">}</span><span class="token string">&#39;)&quot;</span>
<span class="line">echo &quot;IP: $(hostname -I | awk &#39;</span><span class="token punctuation">{</span>print <span class="token variable">$1</span><span class="token punctuation">}</span>&#39;<span class="token punctuation">)</span>&quot;</span>
<span class="line"></span></code></pre></div><h3 id="_8-查找消耗资源最多的进程" tabindex="-1"><a class="header-anchor" href="#_8-查找消耗资源最多的进程"><span>8. 查找消耗资源最多的进程</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 查找 CPU 和内存使用率最高的进程</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;=== CPU 占用 TOP 5 ===&quot;</span></span>
<span class="line"><span class="token function">ps</span> aux <span class="token parameter variable">--sort</span><span class="token operator">=</span>-%cpu <span class="token operator">|</span> <span class="token function">head</span> <span class="token parameter variable">-6</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;=== 内存占用 TOP 5 ===&quot;</span></span>
<span class="line"><span class="token function">ps</span> aux <span class="token parameter variable">--sort</span><span class="token operator">=</span>-%mem <span class="token operator">|</span> <span class="token function">head</span> <span class="token parameter variable">-6</span></span>
<span class="line"></span></code></pre></div><h3 id="_9-检测磁盘空间并发送告警" tabindex="-1"><a class="header-anchor" href="#_9-检测磁盘空间并发送告警"><span>9. 检测磁盘空间并发送告警</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 检测磁盘使用率，超过阈值则告警</span></span>
<span class="line"><span class="token assign-left variable">threshold</span><span class="token operator">=</span><span class="token number">85</span></span>
<span class="line"><span class="token assign-left variable">alert_email</span><span class="token operator">=</span><span class="token string">&quot;admin@example.com&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token function">df</span> <span class="token parameter variable">-h</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-v</span> tmpfs <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-v</span> loop <span class="token operator">|</span> <span class="token keyword">while</span> <span class="token builtin class-name">read</span> line<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token assign-left variable">usage</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$line</span>&quot;</span> <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $5}&#39;</span> <span class="token operator">|</span> <span class="token function">tr</span> <span class="token parameter variable">-d</span> <span class="token string">&#39;%&#39;</span><span class="token variable">)</span></span></span>
<span class="line">    <span class="token assign-left variable">mount</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$line</span>&quot;</span> <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $6}&#39;</span><span class="token variable">)</span></span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$usage</span>&quot;</span> <span class="token parameter variable">-ge</span> <span class="token string">&quot;<span class="token variable">$threshold</span>&quot;</span> <span class="token punctuation">]</span> <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null<span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;⚠️  <span class="token variable">$mount</span> 使用率已达 <span class="token variable">\${usage}</span>%&quot;</span> <span class="token operator">|</span> mail <span class="token parameter variable">-s</span> <span class="token string">&quot;磁盘告警: <span class="token variable">$mount</span>&quot;</span> <span class="token string">&quot;<span class="token variable">$alert_email</span>&quot;</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre></div><h2 id="四、文件处理" tabindex="-1"><a class="header-anchor" href="#四、文件处理"><span>四、文件处理</span></a></h2><h3 id="_10-批量重命名文件" tabindex="-1"><a class="header-anchor" href="#_10-批量重命名文件"><span>10. 批量重命名文件</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 将 article_ 前缀改为 bbs_ 前缀</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">file</span> <span class="token keyword">in</span> article_*.html<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token function">mv</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token string">&quot;bbs_<span class="token variable">\${file<span class="token operator">#</span>article_}</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre></div><h3 id="_11-批量替换文件内容" tabindex="-1"><a class="header-anchor" href="#_11-批量替换文件内容"><span>11. 批量替换文件内容</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 递归替换所有 .conf 文件中的 old_ip 为 new_ip</span></span>
<span class="line"><span class="token assign-left variable">old_ip</span><span class="token operator">=</span><span class="token string">&quot;192.168.1.100&quot;</span></span>
<span class="line"><span class="token assign-left variable">new_ip</span><span class="token operator">=</span><span class="token string">&quot;192.168.1.200&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token function">find</span> /etc <span class="token parameter variable">-name</span> <span class="token string">&quot;*.conf&quot;</span> <span class="token parameter variable">-type</span> f <span class="token parameter variable">-exec</span> <span class="token function">sed</span> <span class="token parameter variable">-i</span> <span class="token string">&quot;s/<span class="token variable">$old_ip</span>/<span class="token variable">$new_ip</span>/g&quot;</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> +</span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;替换完成&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="_12-计算文档中数字总数" tabindex="-1"><a class="header-anchor" href="#_12-计算文档中数字总数"><span>12. 计算文档中数字总数</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 计算文档每行出现的数字个数，并统计总数</span></span>
<span class="line"><span class="token assign-left variable">input_file</span><span class="token operator">=</span><span class="token string">&quot;a.txt&quot;</span></span>
<span class="line"><span class="token assign-left variable">total_lines</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">wc</span> <span class="token parameter variable">-l</span> <span class="token operator">&lt;</span> <span class="token string">&quot;<span class="token variable">$input_file</span>&quot;</span><span class="token variable">)</span></span></span>
<span class="line"><span class="token assign-left variable">total_sum</span><span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">for</span> <span class="token variable"><span class="token punctuation">((</span>i<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span> i<span class="token operator">&lt;=</span>total_lines<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">))</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token assign-left variable">line</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">sed</span> <span class="token parameter variable">-n</span> <span class="token string">&quot;<span class="token variable">\${i}</span>p&quot;</span> <span class="token string">&quot;<span class="token variable">$input_file</span>&quot;</span><span class="token variable">)</span></span></span>
<span class="line">    <span class="token assign-left variable">digit_count</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$line</span>&quot;</span> <span class="token operator">|</span> <span class="token function">sed</span> <span class="token string">&#39;s/[^0-9]//g&#39;</span> <span class="token operator">|</span> <span class="token function">wc</span> <span class="token parameter variable">-L</span><span class="token variable">)</span></span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;第 <span class="token variable">$i</span> 行: <span class="token variable">$digit_count</span> 个数字&quot;</span></span>
<span class="line">    <span class="token assign-left variable">total_sum</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>total_sum <span class="token operator">+</span> digit_count<span class="token variable">))</span></span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;数字总数: <span class="token variable">$total_sum</span>&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="_13-查找并删除空文件" tabindex="-1"><a class="header-anchor" href="#_13-查找并删除空文件"><span>13. 查找并删除空文件</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 删除当前目录下所有空文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> f <span class="token parameter variable">-empty</span> <span class="token parameter variable">-delete</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;空文件已删除&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 删除空目录</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> d <span class="token parameter variable">-empty</span> <span class="token parameter variable">-delete</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;空目录已删除&quot;</span></span>
<span class="line"></span></code></pre></div><h2 id="五、进程管理" tabindex="-1"><a class="header-anchor" href="#五、进程管理"><span>五、进程管理</span></a></h2><h3 id="_14-杀死指定名称的所有进程" tabindex="-1"><a class="header-anchor" href="#_14-杀死指定名称的所有进程"><span>14. 杀死指定名称的所有进程</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 杀死所有匹配名称的进程</span></span>
<span class="line"><span class="token assign-left variable">process_name</span><span class="token operator">=</span><span class="token string">&quot;defunct_process&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token function">ps</span> aux <span class="token operator">|</span> <span class="token function">grep</span> <span class="token string">&quot;<span class="token variable">$process_name</span>&quot;</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-v</span> <span class="token function">grep</span> <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $2}&#39;</span> <span class="token operator">|</span> <span class="token function">xargs</span> <span class="token function">kill</span> <span class="token parameter variable">-9</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;已杀死所有 <span class="token variable">$process_name</span> 进程&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="_15-监控进程是否存在" tabindex="-1"><a class="header-anchor" href="#_15-监控进程是否存在"><span>15. 监控进程是否存在</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 监控进程是否存在，不存在则重启</span></span>
<span class="line"><span class="token assign-left variable">process</span><span class="token operator">=</span><span class="token string">&quot;nginx&quot;</span></span>
<span class="line"><span class="token assign-left variable">restart_cmd</span><span class="token operator">=</span><span class="token string">&quot;/usr/local/nginx/sbin/nginx&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">if</span> <span class="token operator">!</span> pgrep <span class="token parameter variable">-x</span> <span class="token string">&quot;<span class="token variable">$process</span>&quot;</span> <span class="token operator">&gt;</span>/dev/null<span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable"><span class="token variable">$(</span><span class="token function">date</span><span class="token variable">)</span></span> <span class="token variable">$process</span> 已宕机，正在重启...&quot;</span> <span class="token operator">&gt;&gt;</span> /var/log/process_monitor.log</span>
<span class="line">    <span class="token variable">$restart_cmd</span></span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span></code></pre></div><h2 id="六、数据库" tabindex="-1"><a class="header-anchor" href="#六、数据库"><span>六、数据库</span></a></h2><h3 id="_16-mysql-数据库备份" tabindex="-1"><a class="header-anchor" href="#_16-mysql-数据库备份"><span>16. MySQL 数据库备份</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 备份 MySQL 数据库，保留最近 7 天</span></span>
<span class="line"><span class="token assign-left variable">db_user</span><span class="token operator">=</span><span class="token string">&quot;root&quot;</span></span>
<span class="line"><span class="token assign-left variable">db_pass</span><span class="token operator">=</span><span class="token string">&quot;your_password&quot;</span></span>
<span class="line"><span class="token assign-left variable">db_name</span><span class="token operator">=</span><span class="token string">&quot;your_database&quot;</span></span>
<span class="line"><span class="token assign-left variable">backup_dir</span><span class="token operator">=</span><span class="token string">&quot;/backup/mysql&quot;</span></span>
<span class="line"><span class="token assign-left variable">date_str</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> +%Y%m%d_%H%M%S<span class="token variable">)</span></span></span>
<span class="line"></span>
<span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> <span class="token string">&quot;<span class="token variable">$backup_dir</span>&quot;</span></span>
<span class="line">mysqldump -u<span class="token string">&quot;<span class="token variable">$db_user</span>&quot;</span> -p<span class="token string">&quot;<span class="token variable">$db_pass</span>&quot;</span> <span class="token string">&quot;<span class="token variable">$db_name</span>&quot;</span> <span class="token operator">|</span> <span class="token function">gzip</span> <span class="token operator">&gt;</span> <span class="token string">&quot;<span class="token variable">$backup_dir</span>/<span class="token variable">\${db_name}</span>_<span class="token variable">\${date_str}</span>.sql.gz&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 删除 7 天前的备份</span></span>
<span class="line"><span class="token function">find</span> <span class="token string">&quot;<span class="token variable">$backup_dir</span>&quot;</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.sql.gz&quot;</span> <span class="token parameter variable">-mtime</span> +7 <span class="token parameter variable">-delete</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;备份完成: <span class="token variable">\${backup_dir}</span>/<span class="token variable">\${db_name}</span>_<span class="token variable">\${date_str}</span>.sql.gz&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="_17-从-ftp-服务器下载文件" tabindex="-1"><a class="header-anchor" href="#_17-从-ftp-服务器下载文件"><span>17. 从 FTP 服务器下载文件</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 从 FTP 服务器下载指定文件</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token variable">$#</span> <span class="token parameter variable">-ne</span> <span class="token number">1</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;Usage: <span class="token variable">$0</span> filename&quot;</span></span>
<span class="line">    <span class="token builtin class-name">exit</span> <span class="token number">1</span></span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token assign-left variable">dir</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">dirname</span> <span class="token string">&quot;<span class="token variable">$1</span>&quot;</span><span class="token variable">)</span></span></span>
<span class="line"><span class="token assign-left variable">file</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">basename</span> <span class="token string">&quot;<span class="token variable">$1</span>&quot;</span><span class="token variable">)</span></span></span>
<span class="line"></span>
<span class="line"><span class="token function">ftp</span> <span class="token parameter variable">-n</span> <span class="token parameter variable">-v</span> <span class="token operator">&lt;&lt;</span> <span class="token string">EOF</span>
<span class="line">open 192.168.1.10</span>
<span class="line">user admin password</span>
<span class="line">binary</span>
<span class="line">cd <span class="token variable">$dir</span></span>
<span class="line">get &quot;<span class="token variable">$file</span>&quot;</span>
<span class="line">EOF</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="七、交互式脚本" tabindex="-1"><a class="header-anchor" href="#七、交互式脚本"><span>七、交互式脚本</span></a></h2><h3 id="_18-用户猜数字游戏" tabindex="-1"><a class="header-anchor" href="#_18-用户猜数字游戏"><span>18. 用户猜数字游戏</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 生成一个 1-100 的随机数，用户猜数字</span></span>
<span class="line"><span class="token assign-left variable">target</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>RANDOM <span class="token operator">%</span> <span class="token number">100</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token variable">))</span></span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">while</span> <span class="token builtin class-name">:</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">read</span> <span class="token parameter variable">-p</span> <span class="token string">&quot;请输入 1-100 之间的数字: &quot;</span> guess</span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$guess</span>&quot;</span> <span class="token parameter variable">-eq</span> <span class="token string">&quot;<span class="token variable">$target</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;🎉 恭喜，猜对了！&quot;</span></span>
<span class="line">        <span class="token builtin class-name">exit</span> <span class="token number">0</span></span>
<span class="line">    <span class="token keyword">elif</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$guess</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token string">&quot;<span class="token variable">$target</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;📈 猜大了&quot;</span></span>
<span class="line">    <span class="token keyword">else</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;📉 猜小了&quot;</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_19-连续输入数字并统计" tabindex="-1"><a class="header-anchor" href="#_19-连续输入数字并统计"><span>19. 连续输入数字并统计</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># 连续输入 5 个数字，统计和、最小、最大</span></span>
<span class="line"><span class="token assign-left variable">count</span><span class="token operator">=</span><span class="token number">1</span></span>
<span class="line"><span class="token assign-left variable">sum</span><span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"><span class="token assign-left variable">min</span><span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"><span class="token assign-left variable">max</span><span class="token operator">=</span><span class="token number">100</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">while</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$count</span>&quot;</span> <span class="token parameter variable">-le</span> <span class="token number">5</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">read</span> <span class="token parameter variable">-p</span> <span class="token string">&quot;请输入第 <span class="token variable">$count</span> 个整数（1-100）: &quot;</span> num</span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token string">&quot;<span class="token variable">$num</span>&quot;</span> <span class="token operator">=~</span> ^<span class="token punctuation">[</span><span class="token number">0</span>-9<span class="token punctuation">]</span>+$ <span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;输入必须是整数！&quot;</span></span>
<span class="line">        <span class="token builtin class-name">exit</span> <span class="token number">1</span></span>
<span class="line">    <span class="token keyword">elif</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$num</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token number">100</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;输入必须是 100 以内！&quot;</span></span>
<span class="line">        <span class="token builtin class-name">exit</span> <span class="token number">1</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line">    <span class="token assign-left variable">sum</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>sum <span class="token operator">+</span> num<span class="token variable">))</span></span></span>
<span class="line">    <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$min</span>&quot;</span> <span class="token parameter variable">-lt</span> <span class="token string">&quot;<span class="token variable">$num</span>&quot;</span> <span class="token punctuation">]</span> <span class="token operator">&amp;&amp;</span> <span class="token assign-left variable">min</span><span class="token operator">=</span><span class="token variable">$num</span></span>
<span class="line">    <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$max</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token string">&quot;<span class="token variable">$num</span>&quot;</span> <span class="token punctuation">]</span> <span class="token operator">&amp;&amp;</span> <span class="token assign-left variable">max</span><span class="token operator">=</span><span class="token variable">$num</span></span>
<span class="line">    <span class="token assign-left variable">count</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>count <span class="token operator">+</span> <span class="token number">1</span><span class="token variable">))</span></span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;总和: <span class="token variable">$sum</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;最小: <span class="token variable">$min</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;最大: <span class="token variable">$max</span>&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="八、将结果赋值给变量" tabindex="-1"><a class="header-anchor" href="#八、将结果赋值给变量"><span>八、将结果赋值给变量</span></a></h2><h3 id="方法-1-使用-eval" tabindex="-1"><a class="header-anchor" href="#方法-1-使用-eval"><span>方法 1：使用 eval</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token builtin class-name">echo</span> <span class="token string">&quot;4 5 6&quot;</span><span class="token variable">)</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">eval</span> a<span class="token variable">$i</span><span class="token operator">=</span><span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">$a4</span> <span class="token variable">$a5</span> <span class="token variable">$a6</span></span>
<span class="line"></span></code></pre></div><h3 id="方法-2-拆分位置参数" tabindex="-1"><a class="header-anchor" href="#方法-2-拆分位置参数"><span>方法 2：拆分位置参数</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token assign-left variable">num</span><span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token builtin class-name">eval</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$*</span>&quot;</span><span class="token variable">)</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">let</span> <span class="token assign-left variable">num</span><span class="token operator">+=</span><span class="token number">1</span></span>
<span class="line">    <span class="token builtin class-name">eval</span> <span class="token function">node</span><span class="token variable">\${num}</span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable">$i</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">$node1</span> <span class="token variable">$node2</span> <span class="token variable">$node3</span></span>
<span class="line"><span class="token comment"># 执行: bash script.sh 192.168.1.1{1,2}</span></span>
<span class="line"><span class="token comment"># 输出: 192.168.1.11 192.168.1.12</span></span>
<span class="line"></span></code></pre></div><h3 id="方法-3-使用数组" tabindex="-1"><a class="header-anchor" href="#方法-3-使用数组"><span>方法 3：使用数组</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token assign-left variable">arr</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token number">4</span> <span class="token number">5</span> <span class="token number">6</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token assign-left variable">index1</span><span class="token operator">=</span><span class="token variable">\${arr<span class="token punctuation">[</span>0<span class="token punctuation">]</span>}</span></span>
<span class="line"><span class="token assign-left variable">index2</span><span class="token operator">=</span><span class="token variable">\${arr<span class="token punctuation">[</span>1<span class="token punctuation">]</span>}</span></span>
<span class="line"><span class="token assign-left variable">index3</span><span class="token operator">=</span><span class="token variable">\${arr<span class="token punctuation">[</span>2<span class="token punctuation">]</span>}</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">$index1</span> <span class="token variable">$index2</span> <span class="token variable">$index3</span></span>
<span class="line"></span></code></pre></div>`,55)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};